INSERT INTO public.glossary_entries (term, description, category, icon, tags, related_terms, is_published, sort_order) VALUES
('Tages-Cockpit', 'Die zentrale Steuereinheit für deinen Arbeitstag. Kombiniert Route, Navigation, Timer und Fahrtenbuch in einem Screen. Drei Zustände: Bereit (Terminliste), Unterwegs (Navigation), Abschluss (Zusammenfassung).', 'feature', '🗺️', ARRAY['cockpit', 'tour', 'navigation', 'fahrtenbuch'], ARRAY['Turn-by-Turn Navigation', 'Fahrtenbuch', 'OpenRouteService'], true, 91),
('OpenRouteService (ORS)', 'DSGVO-konformer EU-Routing-Dienst der für die Navigation im HufManager genutzt wird. Berechnet optimale Routen, Ankunftszeiten und Sprachansagen – keine Daten an Google.', 'technik', '🧭', ARRAY['navigation', 'dsgvo', 'routing', 'ors'], ARRAY['Tages-Cockpit', 'Turn-by-Turn Navigation'], true, 92),
('Auftragstyp', 'Art des Termins je nach Berufsgruppe (z.B. Barhuf, Eisen, Osteopathie, Zahnbehandlung). Bestimmt die Farbe im Kalender und den automatischen Zeitpuffer nach dem Termin.', 'workflow', '🏷️', ARRAY['termin', 'kalender', 'berufsgruppe', 'zeitpuffer'], ARRAY['Zeitpuffer', 'Berufsgruppe'], true, 93),
('Zeitpuffer', 'Automatisch eingeplante Pufferzeit nach einem Termin. Verhindert Stress durch zu eng getaktete Touren. Die Dauer wird automatisch je nach Auftragstyp und Berufsgruppe gesetzt.', 'workflow', '⏱️', ARRAY['termin', 'tour', 'planung'], ARRAY['Auftragstyp', 'Tages-Cockpit'], true, 94),
('Tankerkönig', 'Deutscher Spritpreis-Dienst der HufManager mit Live-Kraftstoffpreisen versorgt. Zeigt die günstigste Tankstelle auf deiner Route – kostenlos und DSGVO-konform.', 'technik', '⛽', ARRAY['spritpreise', 'tanken', 'dsgvo', 'live'], ARRAY['Tages-Cockpit', 'Fahrtenbuch'], true, 95),
('Stallstandort', 'Ein gespeicherter Standort eines Kunden (z.B. "Reiterhof Müller"). Pferde können verschiedenen Standorten zugewiesen werden. GPS-Koordinaten ermöglichen optimale Routenplanung.', 'daten', '📍', ARRAY['standort', 'stall', 'kunde', 'gps', 'client_locations'], ARRAY['Tages-Cockpit', 'Navigation'], true, 96),
('§6 EStG Fahrtenbuch', 'Steuerlich anerkanntes Fahrtenbuch mit allen Pflichtangaben (Datum, Start/Ziel, km, Anlass). HufManager erstellt es automatisch aus GPS-Daten. Export als PDF oder CSV – steuerfertig.', 'recht', '📋', ARRAY['fahrtenbuch', 'steuer', 'estg', 'gps', 'export'], ARRAY['Tages-Cockpit', 'Tankerkönig'], true, 97);